/**
 * paths.ts — Shared project root resolution
 *
 * Single source of truth for PROJECT_ROOT. Walks up from this file's
 * location to find package.json. All files that need the project root
 * import from here instead of computing it themselves.
 */

import { existsSync } from "fs";
import { join, dirname } from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

function findProjectRoot(startDir: string): string {
  let dir = startDir;
  const root = dirname(dir) === dir ? dir : undefined; // filesystem root guard
  while (dir !== root) {
    if (existsSync(join(dir, "package.json"))) return dir;
    const parent = dirname(dir);
    if (parent === dir) break; // reached filesystem root
    dir = parent;
  }
  throw new Error("Could not find project root (no package.json found)");
}

/** Absolute path to the freddie-ai project root (where package.json lives). */
export const PROJECT_ROOT = findProjectRoot(__dirname);

/** Resolve a path relative to the project root. */
export function fromRoot(...segments: string[]): string {
  return join(PROJECT_ROOT, ...segments);
}

/**
 * Detect the current project identity from the working directory.
 * Returns slug (last path segment) and full path for disambiguation.
 * FREDDIE_PROJECT env var overrides slug if set.
 */
export function detectProject(cwd?: string): { project: string; projectPath: string } {
  const dir = cwd || process.cwd();
  const slug = process.env.FREDDIE_PROJECT || dir.replace(/\\/g, "/").split("/").pop() || "unknown";
  return { project: slug, projectPath: dir };
}

/**
 * Resolve the docs output path for a project.
 * Internal (freddie-ai): vault/studio/projects/{project}/
 * External: {projectPath}/docs/
 */
export function resolveProjectDocsPath(project: string, projectPath: string): string {
  const isInternal = projectPath.replace(/\\/g, "/").endsWith("/freddie-ai") ||
    projectPath.replace(/\\/g, "/").includes("/freddie-ai/");
  if (isInternal) {
    return fromRoot("vault", "studio", "projects", project);
  }
  return join(projectPath, "docs");
}

/**
 * Generate a timestamped document filename.
 * Format: {unix-timestamp-ms}-{slug}.md
 * Slug: lowercase, hyphens for spaces, no special chars.
 */
export function timestampedDocName(title: string): string {
  const ts = Date.now();
  const slug = title
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
  return `${ts}-${slug}.md`;
}

